import React, { useState, useEffect } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
// ✅ CHEMINS CSS CORRIGÉS (sans /esm/)
import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

// Initialiser pdf.js avec le worker CDN
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.js`;

interface PDFViewerProps {
  fileUrl: string;
  onDocumentLoad?: (numPages: number) => void;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl, onDocumentLoad }) => {
  const [numPages, setNumPages] = useState<number | null>(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [scale, setScale] = useState(1.2);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setPageNumber(1);
  }, [fileUrl]);

  const onDocumentSuccess = (pdf: any) => {
    setNumPages(pdf.numPages);
    setLoading(false);
    setError(null);
    if (onDocumentLoad) onDocumentLoad(pdf.numPages);
  };

  const onDocumentError = (err: any) => {
    console.error('Erreur chargement PDF:', err);
    setError('Impossible de charger le PDF. Vérifiez l\'URL ou le format du fichier.');
    setLoading(false);
  };

  const goToPrevPage = () => {
    setPageNumber(prev => Math.max(prev - 1, 1));
  };

  const goToNextPage = () => {
    setPageNumber(prev => Math.min(prev + 1, numPages || 1));
  };

  const zoomIn = () => {
    setScale(prev => Math.min(prev + 0.2, 3.0));
  };

  const zoomOut = () => {
    setScale(prev => Math.max(prev - 0.2, 0.5));
  };

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-800">
      {/* Barre d'outils */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <div className="flex items-center gap-3">
          <button
            onClick={goToPrevPage}
            disabled={pageNumber <= 1}
            className={`p-1.5 rounded-md ${
              pageNumber <= 1
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page précédente (Flèche gauche)"
          >
            <i className="fas fa-chevron-left"></i>
          </button>
          
          <div className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300">
            <span>Page</span>
            <input
              type="number"
              value={pageNumber}
              onChange={(e) => {
                const page = parseInt(e.target.value);
                if (!isNaN(page) && page >= 1 && page <= (numPages || 1)) {
                  setPageNumber(page);
                }
              }}
              min="1"
              max={numPages || 1}
              className="w-12 text-center px-1.5 py-0.5 border border-gray-300 dark:border-gray-600 rounded text-gray-900 dark:text-white"
            />
            <span>sur {numPages || '?'}</span>
          </div>
          
          <button
            onClick={goToNextPage}
            disabled={pageNumber >= (numPages || 1)}
            className={`p-1.5 rounded-md ${
              pageNumber >= (numPages || 1)
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page suivante (Flèche droite)"
          >
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button
            onClick={zoomOut}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md"
            title="Zoom arrière"
          >
            <i className="fas fa-search-minus"></i>
          </button>
          
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
            {Math.round(scale * 100)}%
          </span>
          
          <button
            onClick={zoomIn}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md"
            title="Zoom avant"
          >
            <i className="fas fa-search-plus"></i>
          </button>
          
          <button
            onClick={() => setScale(1.2)}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md"
            title="Zoom par défaut"
          >
            <i className="fas fa-expand"></i>
          </button>
        </div>
        
        <button
          onClick={() => window.open(fileUrl, '_blank')}
          className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-md flex items-center gap-1.5 transition-colors"
          title="Ouvrir dans un nouvel onglet"
        >
          <i className="fas fa-external-link-alt"></i>
          <span className="hidden sm:inline">Ouvrir</span>
        </button>
      </div>
      
      {/* Zone de visualisation */}
      <div className="flex-1 overflow-auto bg-white dark:bg-gray-800 flex items-center justify-center p-4">
        {loading && (
          <div className="text-center">
            <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600 mx-auto mb-3"></div>
            <p className="text-gray-600 dark:text-gray-400">Chargement du PDF...</p>
          </div>
        )}
        
        {error && (
          <div className="text-center max-w-md p-6 bg-red-50 dark:bg-red-900/20 rounded-lg">
            <i className="fas fa-exclamation-triangle text-red-500 text-3xl mb-3"></i>
            <p className="text-red-700 dark:text-red-300 font-medium mb-2">{error}</p>
            <button
              onClick={() => window.open(fileUrl, '_blank')}
              className="mt-3 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-md text-sm flex items-center gap-2 mx-auto"
            >
              <i className="fas fa-file-pdf mr-1.5"></i>
              Ouvrir le PDF directement
            </button>
          </div>
        )}
        
        {!loading && !error && (
          <Document
            file={fileUrl}
            onLoadSuccess={onDocumentSuccess}
            onLoadError={onDocumentError}
            className="max-w-full"
            loading=""
            error=""
          >
            <Page
              pageNumber={pageNumber}
              scale={scale}
              renderTextLayer={true}
              renderAnnotationLayer={true}
              className="shadow-lg rounded-lg"
            />
          </Document>
        )}
      </div>
      
      {/* Indicateur de chargement en bas */}
      {loading && numPages === null && (
        <div className="py-2 px-4 text-center text-sm text-gray-500 dark:text-gray-400 border-t border-gray-200 dark:border-gray-700">
          Préparation du document... (cela peut prendre quelques secondes pour les gros fichiers)
        </div>
      )}
    </div>
  );
};

export default PDFViewer;
